import "./breadcrumb.css";
import { BreadcrumbContext } from "./breadcrumb.context";
import { breadcrumbVariants, type BreadcrumbVariants } from "./breadcrumb.variants";

export type BreadcrumbRootProps = BreadcrumbVariants & React.ComponentProps<"nav">;

export const BreadcrumbRoot = ({ children, ...props }: BreadcrumbRootProps) => {
  const slots = breadcrumbVariants();

  return (
    <BreadcrumbContext value={{ slots }}>
      <nav aria-label="breadcrumb" {...props}>
        {children}
      </nav>
    </BreadcrumbContext>
  );
};

import { cn } from "tailwind-variants";

import { useBreadcrumbContext } from "./breadcrumb.context";

export type BreadcrumbListProps = React.ComponentProps<"ol">;

export const BreadcrumbList = ({ className, ...props }: BreadcrumbListProps) => {
  const { slots } = useBreadcrumbContext();
  return <ol className={cn(slots.list(), className)} {...props} />;
};

import { cn } from "tailwind-variants";

import { useBreadcrumbContext } from "./breadcrumb.context";

export type BreadcrumbItemProps = React.ComponentProps<"li">;

export const BreadcrumbItem = ({ className, ...props }: BreadcrumbItemProps) => {
  const { slots } = useBreadcrumbContext();
  return <li className={cn(slots.item(), className)} {...props} />;
};

import { cn } from "tailwind-variants";

import { useBreadcrumbContext } from "./breadcrumb.context";

export type BreadcrumbLinkProps = React.ComponentProps<"a">;

export const BreadcrumbLink = ({ className, ...props }: BreadcrumbLinkProps) => {
  const { slots } = useBreadcrumbContext();
  return <a className={cn(slots.link(), className)} {...props} />;
};

import { cn } from "tailwind-variants";

import { useBreadcrumbContext } from "./breadcrumb.context";

export type BreadcrumbPageProps = React.ComponentProps<"span">;

export const BreadcrumbPage = ({ className, ...props }: BreadcrumbPageProps) => {
  const { slots } = useBreadcrumbContext();
  return (
    <span
      aria-current="page"
      aria-disabled="true"
      className={cn(slots.page(), className)}
      role="link"
      {...props}
    />
  );
};

import { ChevronRight } from "lucide-react";
import { cn } from "tailwind-variants";

import { useBreadcrumbContext } from "./breadcrumb.context";

export type BreadcrumbSeparatorProps = React.ComponentProps<"li">;

export const BreadcrumbSeparator = ({
  children,
  className,
  ...props
}: BreadcrumbSeparatorProps) => {
  const { slots } = useBreadcrumbContext();
  return (
    <li
      aria-hidden="true"
      className={cn(slots.separator(), className)}
      role="presentation"
      {...props}
    >
      {children ?? <ChevronRight className="size-3.5" />}
    </li>
  );
};

import { MoreHorizontal } from "lucide-react";
import { cn } from "tailwind-variants";

import { useBreadcrumbContext } from "./breadcrumb.context";

export type BreadcrumbEllipsisProps = React.ComponentProps<"span">;

export const BreadcrumbEllipsis = ({ className, ...props }: BreadcrumbEllipsisProps) => {
  const { slots } = useBreadcrumbContext();
  return (
    <span
      aria-hidden="true"
      className={cn(slots.ellipsis(), className)}
      role="presentation"
      {...props}
    >
      <MoreHorizontal className="size-4" />
      <span className="sr-only">More</span>
    </span>
  );
};

import { createContext, useContext } from "react";

import { breadcrumbVariants } from "./breadcrumb.variants";

export type BreadcrumbContext = {
  slots: ReturnType<typeof breadcrumbVariants>;
};

export const BreadcrumbContext = createContext<BreadcrumbContext | null>(null);

export const useBreadcrumbContext = () => {
  const context = useContext(BreadcrumbContext);
  if (!context) {
    throw new Error("useBreadcrumbContext must be used within a Breadcrumb.Root");
  }
  return context;
};

/* eslint-disable perfectionist/sort-objects */

import { tv, type VariantProps } from "tailwind-variants";

export const breadcrumbVariants = tv({
  slots: {
    root: "breadcrumb",
    list: "breadcrumb__list",
    item: "breadcrumb__item",
    link: "breadcrumb__link",
    page: "breadcrumb__page",
    separator: "breadcrumb__separator",
    ellipsis: "breadcrumb__ellipsis",
  },
});

export type BreadcrumbVariants = VariantProps<typeof breadcrumbVariants>;

.breadcrumb__list {
  @apply text-muted-foreground flex flex-wrap items-center gap-1.5 text-sm break-words sm:gap-2.5;
}

.breadcrumb__item {
  @apply inline-flex items-center gap-1.5;
}

.breadcrumb__link {
  @apply hover:text-foreground transition-colors;
}

.breadcrumb__page {
  @apply text-foreground font-normal;
}

.breadcrumb__separator {
  @apply [&>svg]:size-3.5;
}

.breadcrumb__ellipsis {
  @apply flex size-9 items-center justify-center;
}

import { BreadcrumbEllipsis } from "./breadcrumb-ellipsis";
import { BreadcrumbItem } from "./breadcrumb-item";
import { BreadcrumbLink } from "./breadcrumb-link";
import { BreadcrumbList } from "./breadcrumb-list";
import { BreadcrumbPage } from "./breadcrumb-page";
import { BreadcrumbRoot } from "./breadcrumb-root";
import { BreadcrumbSeparator } from "./breadcrumb-separator";

export const Breadcrumb = {
  Ellipsis: BreadcrumbEllipsis,
  Item: BreadcrumbItem,
  Link: BreadcrumbLink,
  List: BreadcrumbList,
  Page: BreadcrumbPage,
  Root: BreadcrumbRoot,
  Separator: BreadcrumbSeparator,
};

export {
  BreadcrumbEllipsis,
  BreadcrumbItem,
  BreadcrumbLink,
  BreadcrumbList,
  BreadcrumbPage,
  BreadcrumbRoot,
  BreadcrumbSeparator,
};

export type { BreadcrumbEllipsisProps } from "./breadcrumb-ellipsis";

export type { BreadcrumbItemProps } from "./breadcrumb-item";

export type { BreadcrumbLinkProps } from "./breadcrumb-link";
export type { BreadcrumbListProps } from "./breadcrumb-list";
export type { BreadcrumbPageProps } from "./breadcrumb-page";
export type { BreadcrumbRootProps } from "./breadcrumb-root";
export type { BreadcrumbSeparatorProps } from "./breadcrumb-separator";
export { BreadcrumbContext, useBreadcrumbContext } from "./breadcrumb.context";
export { type BreadcrumbVariants, breadcrumbVariants } from "./breadcrumb.variants";
